fn solve(s: String, k: i64) -> String {
    let mut result: Vec<char> = Vec::new();
    for c in s.chars() {
        match c {
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let mut clone = result.clone();
                result.extend(clone);
            },
            '%' => {
                result.reverse();
            },
            _ => {
                result.push(c);
            }
        }
    }
    if k < 0 || k >= result.len() as i64 {
        return String::from(".");
    }
    return String::from(result[k as usize]);
}
